INSERT INTO cbt_soal VALUES("522"," PAK","PAK","","1","","Dalam kehidupan sehari-hari, seorang siswa Kristen berusaha berlaku jujur saat ujian walaupun tidak diawasi guru. Sikap tersebut mencerminkan penerapan etika Kristen yang berdasarkan pada ajaran Yesus dalam Alkitab, yaitu â¦.","","","","Hidup dalam kebenaran dan kejujuran","Mengutamakan kepentingan pribadi","Mencari pujian dari orang lain","Takut terhadap hukuman semata","Menghindari tanggung jawab","","","","","","1","0","0","0","0","0");
