INSERT INTO cbt_soal VALUES("524"," PAK","PAK","","3","","Seorang siswa tetap bersikap sabar dan tidak membalas ketika diejek oleh temannya. Ia memilih mendoakan temannya tersebut. Sikap ini menunjukkan ciri kedewasaan rohani, yaitu â¦.","","","","Mudah tersinggung dan marah","Mengandalkan emosi pribadi","Menguasai diri dan hidup dalam kasih","Mencari pembenaran diri","Menunjukkan kekuatan agar dihormati","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("525"," PAK","PAK","","4","","Maria aktif dalam kegiatan gereja dan sekolah. Ketika ia melakukan kesalahan dalam sebuah kegiatan, ia tidak menyalahkan orang lain. Ia mau mengakui kesalahannya dan belajar agar menjadi lebih baik. Sikap ini sesuai dengan ajaran Rasul Paulus tentang pertumbuhan iman.<BR>Perilaku Maria mencerminkan bahwa ia â¦.","","","","Ingin dipuji oleh pembina","Takut kehilangan jabatan","Berusaha menutupi kesalahan","Bertumbuh dalam kerendahan hati dan tanggung jawab","Menunjukkan dirinya lebih baik dari orang lain","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("526"," PAK","PAK","","5","","Rina memiliki pacar yang sering mengajaknya melakukan hal-hal yang tidak sesuai dengan ajaran Kristen. Rina menolak dengan tegas namun tetap berbicara dengan sopan. Ia menjelaskan bahwa dalam pacaran, ia ingin tetap hidup sesuai ajaran Yesus Kristus.<BR>Sikap Rina menunjukkan bahwa dalam pacaran, seorang Kristen harus â¦.","","","","Mengikuti semua kemauan pasangan","Takut kehilangan pasangan","Bersikap kasar agar dihormati","Menuruti tekanan agar diterima","Teguh mempertahankan nilai iman","","","","","","5","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("527"," PAK","PAK","","6","","Budi dan Siska sering berselisih paham karena perbedaan karakter. Namun mereka memilih menyelesaikan masalah dengan komunikasi yang baik, saling memaafkan, dan tidak menyebarkan masalah mereka kepada teman-teman.<BR>Sikap tersebut mencerminkan bahwa pacaran yang dewasa secara rohani adalah â¦.","","","","Hubungan yang penuh emosi dan pertengkaran","Hubungan yang mengutamakan gengsi","Hubungan yang harus selalu sempurna tanpa masalah","Hubungan yang dibangun atas komunikasi, pengampunan, dan kedewasaan","Hubungan yang bergantung pada pendapat orang lain","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("528"," PAK","PAK","","7","","Arman sering menghadapi tantangan dalam pergaulan. Ia pernah hampir terpengaruh untuk melakukan hal yang tidak baik, tetapi ia memilih berdoa dan meminta nasihat dari pembina rohaninya. Ia ingin terus bertumbuh dalam iman.<BR>Tindakan Arman menunjukkan bahwa pertumbuhan rohani ditandai dengan â¦.","","","","Mengandalkan kekuatan diri sendiri","Mengikuti arus pergaulan","Kesadaran untuk belajar dan memperbaiki diri","Menghindari semua pergaulan","Menyalahkan orang lain atas kelemahan diri","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("529"," PAK","PAK","","8","","Niko dikenal sebagai siswa yang sabar dan ramah. Ketika temannya melakukan kesalahan dalam kerja kelompok, ia tidak marah, tetapi membantu memperbaikinya. Sikapnya membuat suasana kelompok menjadi damai. Perilaku Niko mencerminkan buah Roh sebagaimana diajarkan oleh Rasul Paulus, yaitu â¦.","","","","Kemarahan dan ambisi pribadi","Kesabaran dan kasih","Keinginan untuk menang sendiri","Sikap acuh tak acuh","Mencari pujian dari teman","","","","","","2","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("530"," PAK","PAK","","9","","Lina tetap bersukacita walaupun nilainya tidak sesuai harapan. Ia percaya Tuhan memiliki rencana yang baik dan ia berusaha belajar lebih giat tanpa menyalahkan siapa pun.<BR>Sikap Lina menunjukkan salah satu buah Roh, yaitu â¦.","","","","Sukacita dan penguasaan diri","Keraguan","Iri hati","Keputusasaan","Kesombongan","","","","","","1","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("531"," PAK","PAK","","10","","Pengorban Tuhan Yesus buat menyelamatkan manusia, yaitu dengan rela di tangkap, disiksa, dicambuk, bahkan mati di kayu Salib. Pengorbanan itu adalha bentuk kasih Nya kepada manusia yang berdosa, supaya dosa nya di hapuskan. Hal ini merupakan bentuk kasih â¦","","","","Storge.","Agape","Philia","Eros","Maria","","","","","","2","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("532"," PAK","PAK","","11","","adalah â¦.","","","","Menghindari pembahasan masalah","Menyerahkan keputusan pada satu orang saja","Mengambil keputusan melalui musyawarah bersama","Membiarkan konflik tanpa penyelesaian","Memilih berdasarkan emosi","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("533"," PAK","PAK","","12","","Di kelas Pendidikan Agama, guru meminta siswa memilih ketua kelompok secara terbuka dan jujur. Setiap siswa diberi hak untuk memilih tanpa tekanan. Guru menekankan bahwa setiap orang memiliki nilai yang sama di hadapan Tuhan.<BR>Sikap tersebut sesuai dengan ajaran Yesus Kristus tentang menghargai setiap pribadi. Prinsip demokrasi yang terlihat adalah â¦.","","","","Diskriminasi terhadap siswa tertentu","Mengutamakan siswa yang paling populer","Pemaksaan pilihan oleh guru","Penghargaan terhadap kesetaraan dan keadilan","Mengabaikan hak suara sebagian siswa","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("534"," PAK","PAK","","13","","Dalam sebuah diskusi kelas, guru mengajarkan bahwa setiap orang berhak menyampaikan pendapat dengan sopan. Hal ini sejalan dengan prinsip Alkitab yang menekankan kasih dan penghargaan terhadap sesama, sebagaimana diajarkan oleh Yesus Kristus.<BR>Nilai HAM yang tercermin dalam peristiwa tersebut adalah â¦.","","","","Membatasi kebebasan orang lain","Mengutamakan kepentingan diri sendiri","Mengabaikan suara minoritas","Menghakimi pendapat yang berbeda","Menghormati martabat dan hak setiap orang","","","","","","5","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("535"," PAK","PAK","","14","","Rapat pemuda gereja membahas pembagian tugas pelayanan. Semua anggota diberi kesempatan yang sama tanpa membedakan suku atau latar belakang. Mereka mengingat ajaran para rasul tentang hidup dalam kasih dan persatuan, seperti yang dicontohkan oleh Rasul Paulus.<BR>Sikap tersebut mencerminkan prinsip HAM dalam Alkitab, yaitu â¦.","","","","Diskriminasi dalam pelayanan","Keutamaan kelompok tertentu","Pemaksaan kehendak pemimpin","Pembatasan partisipasi anggota","Persamaan derajat dan keadilan","","","","","","5","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("536"," PAK","PAK","","15","","Di kelas, terdapat siswa yang berasal dari berbagai suku dan budaya. Saat kerja kelompok, mereka saling menghargai perbedaan bahasa dan kebiasaan masing-masing. Guru mengingatkan bahwa dalam Kristus semua orang dipersatukan dalam kasih.<BR>Sikap para siswa tersebut mencerminkan nilai multikultural menurut Alkitab, yaitu â¦.","","","","Mengutamakan budaya sendiri","Menolak perbedaan","Menghindari kerja sama","Membentuk kelompok berdasarkan suku","Menghargai keberagaman dalam persatuan","","","","","","5","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("537"," PAK","PAK","","16","","Tuhan Yesus mempunyai dua belas murid, tetapi diantaranya ada satu murid yang mengkianati nya, yaitu ia menjual Tuhan Yesus, kepada ahli torat dan orang Farizi, sehingga akhirnya Yesus ditangkap. Siapakah nama murid","","","","Petrus","Thomas","Yakobus","Yudas Iskariot","Yohanes","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("538"," PAK","PAK","","17","","Andreas dan Lydia sedang mempersiapkan diri menuju pernikahan. Mereka sepakat untuk saling setia, saling menghormati, dan membangun rumah tangga dengan doa serta komunikasi yang baik karena mereka percaya pernikahan adalah anugerah Tuhan.<BR>Berdasarkan cerita tersebut, makna pernikahan menurut Alkitab adalah â¦.","","","","Hubungan sementara yang bergantung perasaan","Ikatan yang mudah diputuskan","Hubungan untuk kepentingan pribadi","Perjanjian kudus yang dibangun atas kasih dan tanggung jawab","Ikatan yang hanya diatur adat","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("539"," PAK","PAK","","18","","Di siksa, di aniaya, di cambuk, dimahkotai duri, serta disalib dan kemudia Ia mati, di kuburkan, tetapi tidak selama nya Ia mati, Dia menunjukan Bhawa Yesus adalah Allah, oleh sebab itu maka Ia bangkit. Pada hari keberapaa..","","","","hari ke tujuh","hari ke lima","hari ke empat","hari ke tiga","hari ke empat puluh","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("540"," PAK","PAK","","19","","Dalam surat-suratnya, Rasul Paulus mengajarkan bahwa orang-orang percaya adalah satu tubuh dengan banyak anggota. Setiap orang memiliki peran yang berbeda namun saling melengkapi.<BR>Makna Keluarga Allah berdasarkan ajaran tersebut adalah â¦.","","","","Setiap orang bekerja sendiri-sendiri","Hanya pemimpin yang berperan penting","Semua anggota saling membutuhkan dan melengkapi","Perbedaan menjadi alasan perpecahan","Pelayanan hanya untuk kelompok tertentu","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("541"," PAK","PAK","","20","","Dalam persekutuan pemuda, setiap anggota diberi kesempatan untuk berpartisipasi sesuai talenta masing-masing. Pemimpin mengingatkan ajaran Rasul Paulus tentang hidup sebagai satu tubuh yang saling melengkapi.<BR>Makna pertumbuhan rohani melalui aspek sosial berdasarkan peristiwa tersebut adalah â¦.","","","","Menonjolkan kemampuan pribadi","Bersaing untuk menjadi yang terbaik","Bertumbuh bersama dalam kerja sama dan pelayanan","Mengabaikan peran anggota lain","Membatasi pelayanan pada kelompok tertentu","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("542"," PAK","PAK","","21","","Kevin menemukan dompet di halaman sekolah yang berisi uang dan kartu identitas. Ia sempat tergoda untuk menyimpannya, tetapi ia memilih menyerahkannya kepada guru agar dikembalikan kepada pemiliknya. Kevin percaya bahwa Tuhan menghendaki kejujuran dalam setiap tindakan.<BR>Sikap Kevin menunjukkan pertumbuhan dalam aspek moral, yaitu â¦.","","","","Mencari keuntungan pribadi","Takut dihukum guru","Memilih yang benar meskipun ada godaan","Ingin mendapat pujian","Menghindari tanggung jawab","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("543"," PAK","PAK","","22","","Seorang pemimpin dipanggil Tuhan untuk membawa bangsa Israel keluar dari perbudakan di Mesir. Walaupun awalnya merasa tidak mampu, ia taat pada panggilan Tuhan dan memimpin umat menuju kebebasan.<BR>Tokoh Alkitab yang diceritakan tersebut adalah â¦.","","","","Yosua","Musa","Petrus","Paulus","Yusuf","","","","","","2","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("544"," PAK","PAK","","23","","Seorang rasul dahulu pernah menganiaya orang-orang percaya, tetapi setelah mengalami perjumpaan dengan Tuhan, hidupnya berubah total dan ia menjadi pemberita Injil yang setia. Ia menulis banyak surat kepada jemaat.<BR>Tokoh yang dimaksud adalah â¦.","","","","Yohanes","Petrus","Yakobus","Rasul Paulus","Tomas","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("545"," PAK","PAK","","24","","Dalam sebuah khotbah Paskah, pendeta menjelaskan bahwa kebangkitan Kristus memberi harapan dan hidup yang baru bagi setiap orang yang percaya. Jemaat diajak untuk hidup dalam pertobatan dan sukacita.<BR>Sikap yang sesuai dengan makna Paskah adalah â¦.","","","","Hidup dalam keputusasaan","Mengabaikan pengorbanan Kristus","Mensyukuri keselamatan dan hidup dalam kebenaran","Merayakan tanpa memahami maknanya","Menjadikan Paskah sekadar rutinitas","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("546"," PAK","PAK","","25","","Dalam ibadah Jumat Agung, jemaat merenungkan penderitaan dan kematian Yesus di kayu salib. Mereka diajak untuk hidup dalam pertobatan dan meninggalkan dosa sebagai respons atas pengorbanan-Nya.<BR>Sikap yang sesuai dengan makna penyaliban adalah â¦.","","","","Menganggap dosa sebagai hal biasa","Mengabaikan pengorbanan Kristus","Hidup dalam pertobatan dan ketaatan","Menjadikan peristiwa itu sekadar tradisi","Menyalahkan orang lain atas penderitaan Yesus","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("547"," PAK","PAK","","26","","Ketika disalibkan, Yesus Kristus tetap menunjukkan kasih dengan mengampuni orang-orang yang menyiksa-Nya. Sikap ini menjadi teladan bagi orang percaya.<BR>Nilai utama yang dapat dipelajari dari peristiwa tersebut adalah â¦.","","","","Balas dendam terhadap musuh","Kebencian terhadap penindas","Kasih dan pengampunan","Keputusasaan dalam penderitaan","Penolakan terhadap kehendak Tuhan","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("548"," PAK","PAK","","27","","Tuhan Yesus di dalibkan di sebuah tempat yang benama","","","","GOLGOTA","SAMARIA","GALILEA","PETRA","YEHUDA","","","","","","1","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("549"," PAK","PAK","","28","","Ada du belas murid Tuhan Yesus yang semua nya setia, tetapi pada waktu Tuhan Yesus di tangkap dan disiksa ad salah satu murid yangmenyangkal, bahwa ia tidak kenal dantidak tau tentang Tuhan Yesus. Murid tersebut bernama..","","","","MATIUS","SAULUS","YUDAS","SIMON","PETRUS","","","","","","5","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("550"," PAK","PAK","","29","","Alkitab seluruhnya berjumlah 66 kitab, yang terdiri dariâ¦.","","","","Perjanjian lama 33 dan Perjanian Baru 33","Perjanjian Lama 17 dan Perjanjian Baru 49","Perjanjian Lama 26 dan Perjanjian Baru 40","Perjanjian lama 29 dan Perjanjian Baru 37","Perjanjian Lama 39 dan Perjanjian Baru 27","","","","","","5","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("551"," PAK","PAK","","30","","Setelah kenaikan Tuhan Yesus, para murid berkumpul dan berdoa dengan tekun. Pada hari Pentakosta, mereka dipenuhi kuasa dari atas sehingga berani memberitakan Injil kepada banyak orang.<BR>Peristiwa tersebut menunjukkan peran Roh Kudus sebagai â¦.","","","","Pengganti pemimpin manusia","Sumber ketakutan dan kebingungan","Penolong dan pemberi kuasa bagi orang percaya","Simbol perayaan semata","Tanda kehebatan pribadi murid-murid","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("552"," PAK","PAK","","31","","Dina merasa ragu saat harus memilih antara berbohong atau berkata jujur. Ia berdoa dan merasakan dorongan dalam hatinya untuk melakukan yang benar. Ia percaya Roh Kudus menuntunnya dalam mengambil keputusan.<BR>Peran Roh Kudus dalam cerita tersebut adalah â¦.","","","","Membiarkan manusia menentukan jalan sendiri","Menuntun pada kebenaran","Menghukum tanpa memberi kesempatan","Mengabaikan pergumulan manusia","Memberi kebebasan tanpa arah","","","","","","2","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("553"," PAK","PAK","","32","","Dalam khotbah di bukit, Tuhan Yesus mengajarkan bahwa pengikut-Nya adalah terang dunia yang tidak boleh disembunyikan. Pesan tersebut mengingatkan orang percaya untuk hidup berbeda dan memberi dampak positif di tengah masyarakat.<BR>Makna menjadi terang bagi orang percaya adalah â¦.","","","","Hidup sama seperti lingkungan sekitar tanpa prinsip","Menyembunyikan iman agar aman","Memancarkan kebaikan dan kebenaran dalam kehidupan sehari-hari","Menganggap diri lebih suci dari orang lain","Mengisolasi diri dari masyarakat","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("554"," PAK","PAK","","33","","Dalam kerja kelompok, semua anggota saling menyalahkan ketika terjadi kesalahan. Namun Siska memilih mengakui kekurangannya dan mengajak teman-temannya memperbaiki bersama. Sikapnya membuat suasana menjadi damai.<BR>Perilaku Siska menunjukkan makna menjadi terang, yaitu â¦.","","","","Memperkeruh suasana","Membiarkan konflik berlanjut","Membawa damai dan solusi","Menyalahkan orang lain","Menghindari tanggung jawab","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("555"," PAK","PAK","","34","","Lina memiliki kemampuan bernyanyi yang baik. Ia menggunakan talentanya untuk melayani dalam ibadah dan menghibur orang-orang yang sedang sedih. Ia meneladani ajaran Yesus Kristus untuk melayani dengan kasih.<BR>Sikap Lina menunjukkan bahwa menjadi berkat berarti â¦.","","","","Menyimpan talenta untuk diri sendiri","Menggunakan kemampuan untuk membanggakan diri","Memakai talenta untuk membangun dan melayani","Menolak kesempatan pelayanan","Membandingkan diri dengan orang lain","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("556"," PAK","PAK","","35","","Di kelas, Riko melihat temannya kesulitan memahami pelajaran Matematika. Setelah jam sekolah, Riko dengan sabar membantu menjelaskan materi tanpa meminta imbalan. Ia percaya bahwa hidupnya di sekolah harus membawa dampak positif bagi orang lain.<BR>Sikap Riko menunjukkan arti menjadi berkat di lingkungan sekolah, yaitu â¦.","","","","Membantu agar dianggap pintar","Menolong dengan tulus demi kebaikan bersama","Mencari perhatian guru","Mengharapkan balasan dari teman","Menunjukkan kelebihan diri","","","","","","2","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("557"," PAK","PAK","","36","","Hukum Torat ada sepuluh dan salah satunya ada yang berbunyi â Hormatilah Ayahmu dan Ibumu, supaya lanjut umurmu di tanah yang diberikan Tjhan Allahmu kepamuâ. Adalah bunyi hukum Torat yang ke berapa ?","","","","Sembilan","Delapan","tujuh","Lima","Tiga","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("558"," PAK","PAK","","37","","Musa menulis kitab ada lima, yaitu ,Kecuali","","","","Kejadian,","Keluaran","Bilanagan","Mazmur","Ulangan","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("559"," PAK","PAK","","38","","Buah-Buah Roh itu ada sembilan di tulis dalam kitab","","","","Lukas","Matius","Yohanes","Galatia","Efesus","","","","","","4","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("560"," PAK","PAK","","39","","Sembilan Buah Roh, dan yang ketiga berbunyiâ¦..","","","","Kasih","Kesabaran","Suka cita","Kemurahan","Damai Sejahtera","","","","","","5","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("561"," PAK","PAK","","40","","Di lingkungan tempat tinggalnya, Rendi aktif membantu kegiatan kerja bakti tanpa membedakan latar belakang agama atau suku warga. Ia percaya bahwa sebagai orang Kristen, ia harus menunjukkan kasih kepada semua orang.<BR>Sikap Rendi mencerminkan nilai Kristiani dalam masyarakat, yaitu â¦.","","","","Mengutamakan kelompok sendiri","Bersikap acuh terhadap lingkungan","Kasih dan kepedulian terhadap sesama","Mencari pujian dari warga","Berpartisipasi hanya jika diminta","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("562"," PAK","PAK","","41","","Di lingkungan tempat tinggalnya, Ardi sering terlibat dalam kegiatan sosial. Ketika ada warga yang berbeda keyakinan mengalami kesulitan, ia tetap membantu dengan tulus tanpa membeda-bedakan. Ia percaya imannya harus diwujudkan dalam tindakan nyata.<BR>Sikap Ardi menunjukkan kedewasaan iman karena ia â¦.","","","","Membantu agar dianggap baik","Hanya peduli pada kelompok sendiri","Menghidupi kasih dalam tindakan nyata","Menghindari tanggung jawab sosial","Menolong jika ada imbalan","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("563"," PAK","PAK","","42","","Di sebuah desa, masyarakat terdiri dari berbagai suku dan agama. Saat perayaan hari besar salah satu kelompok, warga lain ikut membantu menjaga keamanan dan ketertiban tanpa ikut dalam ibadahnya. Mereka saling menghormati dan menjaga kerukunan.<BR>Sikap tersebut mencerminkan nilai multikultural, yaitu â¦.","","","","Mengutamakan kelompok sendiri","Toleransi dan saling menghargai perbedaan","Menghindari interaksi dengan kelompok lain","Membatasi kerja sama antarwarga","Memaksakan keyakinan kepada orang lain","","","","","","2","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("564"," PAK","PAK","","43","","Seorang pemuda Kristen aktif dalam kegiatan lintas agama di lingkungannya. Ia meneladani ajaran Yesus Kristus tentang kasih kepada sesama tanpa membeda-bedakan.<BR>Tindakan tersebut menunjukkan bahwa nilai multikultural sejalan dengan nilai Kristiani, yaitu ....","","","","Menutup diri dari perbedaan","Menganggap budaya sendiri paling benar","Menghargai martabat setiap manusia","Menghindari dialog antaragama","Membatasi pergaulan sosial","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("565"," PAK","PAK","","44","","Perkembangan teknologi medis membantu banyak orang sembuh dari penyakit. Dalam iman Kristen, kemajuan IPTEK dipandang sebagai â¦.","","","","Bukti manusia tidak membutuhkan Tuhan","Ancaman bagi kehidupan rohani","Karunia Tuhan yang harus dipakai untuk kebaikan","Sarana untuk menyombongkan diri","Alat untuk bersaing tanpa etika","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("566"," PAK","PAK","","45","","Guru menjelaskan bahwa manusia diberi akal budi untuk mengelola dunia dengan baik. Prinsip ini sejalan dengan mandat budaya dalam Kitab Kejadian.<BR>Tokoh yang menunjukkan bahwa hikmat dan pengetahuan berasal dari Tuhan adalah â¦.","","","","Salomo","Firaun","Goliat","Herodes","Yudas Iskariot","","","","","","1","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("567"," PAK","PAK","","46","","Seorang remaja Kristen menolak ajakan temannya untuk menyontek saat ujian, meskipun ia takut nilainya rendah. Ia memilih jujur dan menerima konsekuensinya.<BR>Tindakan tersebut mencerminkan kedewasaan yang bertanggung jawab karena â¦.","","","","Mengutamakan hasil daripada proses","Menjaga integritas dan kejujuran","Takut kepada guru","Ingin terlihat berbeda","Menghindari persaingan","","","","","","2","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("568"," PAK","PAK","","47","","Dalam Alkitab, rasul Paulus menasihati jemaat agar bertumbuh menjadi dewasa dalam iman dan tidak lagi seperti anak-anak dalam pemikiran.<BR>Sikap yang menunjukkan kedewasaan rohani yang bertanggung jawab adalah â¦.","","","","Mudah terpengaruh ajaran yang salah","Mengabaikan nasihat rohani","Hidup disiplin, setia, dan taat pada firman Tuhan","Mengikuti arus tanpa pertimbangan","Bersikap egois dalam pelayanan","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("569"," PAK","PAK","","48","","Dalam kegiatan kerja bakti di kampung, remaja gereja ikut berpartisipasi bersama pemuda dari latar belakang yang berbeda. Mereka bekerja sama demi kebersihan lingkungan.<BR>Peran tersebut mencerminkan nilai Kristiani yang diajarkan oleh â¦.","","","","Firaun","Herodes","Yesus Kristus","Pontius Pilatus","Goliat","","","","","","3","0","0","0","0","0");
INSERT INTO cbt_soal VALUES("570"," PAK","PAK","","49","","Seorang siswa menolak untuk berbohong meskipun tidak ada yang melihat. Ia percaya bahwa Tuhan mengetahui segala sesuatu.<BR>Tindakan tersebut menunjukkan bahwa takut akan Tuhan mendorong seseorang untuk â¦.","","","","Takut kepada manusia","Bertindak jujur dalam segala situasi","Mencari pujian dari orang lain","Menghindari pergaulan","Bersikap egois","","","","","","2","0","0","0","0","0");
